To implement advanced generation options for images, I will update the application to support Style Presets, Negative Prompts, and Seed control.

Here is the plan:
1.  **Update `types.ts`** to include an `AdvancedOptions` interface and add it to the `GeneratedItem` type for history tracking.
2.  **Update `services/gemini.ts`** to accept these options in `generateImage`. Since the API config for `generateImages` is strict, I will implement Style and Negative Prompts via prompt engineering (appending instructions) and pass the `seed` in the configuration object.
3.  **Update `App.tsx`** to add the UI controls (Accordion with Style dropdown, Negative Prompt input, and Seed input) and manage the new state variables.

# Updated files:

## types.ts

Add `AdvancedOptions` interface and update `GeneratedItem` to include these options.

```typescript
export enum MediaType {
  IMAGE = 'IMAGE',
  VIDEO = 'VIDEO',
}

export interface AdvancedOptions {
  stylePreset?: string;
  negativePrompt?: string;
  seed?: number;
}

export interface GeneratedItem {
  id: string;
  type: MediaType;
  url: string;
  prompt: string;
  timestamp: number;
  aspectRatio: string;
  advancedOptions?: AdvancedOptions;
}

export type AspectRatio = '1:1' | '16:9' | '9:16' | '4:3' | '3:4';

export interface GenerationConfig {
  prompt: string;
  aspectRatio: AspectRatio;
  mediaType: MediaType;
}

// Global augmentation for the AI Studio key selection
declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }

  interface Window {
    aistudio?: AIStudio;
  }
}
```

## services/gemini.ts

Update `generateImage` to handle `AdvancedOptions` by modifying the prompt and configuration.

```typescript
import { GoogleGenAI } from "@google/genai";
import { MediaType, AspectRatio, AdvancedOptions } from '../types';

// Models
const IMAGEN_MODEL = 'imagen-4.0-generate-001';
const VEO_MODEL = 'veo-3.1-fast-generate-preview';

export const checkApiKeySelection = async (): Promise<void> => {
  if (window.aistudio) {
    const hasKey = await window.aistudio.hasSelectedApiKey();
    if (!hasKey) {
      await window.aistudio.openSelectKey();
    }
  }
};

// Helper to convert Blob to Base64 for storage persistence
const blobToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve(reader.result as string);
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

export const generateImage = async (
  prompt: string,
  aspectRatio: AspectRatio,
  options?: AdvancedOptions
): Promise<string> => {
  // Always instantiate fresh to capture any key updates
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Construct enhanced prompt based on advanced options
  let finalPrompt = prompt;

  if (options?.stylePreset && options.stylePreset !== 'None') {
    finalPrompt += `. Style: ${options.stylePreset}`;
  }

  if (options?.negativePrompt) {
    // Appending negative prompt instruction is a robust way to handle exclusions
    finalPrompt += `. (Exclude: ${options.negativePrompt})`;
  }

  // Prepare config
  const config: any = {
    numberOfImages: 1,
    outputMimeType: 'image/jpeg',
    aspectRatio: aspectRatio,
  };

  // Add seed if provided
  if (options?.seed !== undefined && options.seed !== null) {
    config.seed = options.seed;
  }

  try {
    const response = await ai.models.generateImages({
      model: IMAGEN_MODEL,
      prompt: finalPrompt,
      config: config,
    });

    const base64ImageBytes = response.generatedImages?.[0]?.image?.imageBytes;
    if (!base64ImageBytes) {
      throw new Error("No image data returned from API.");
    }

    return `data:image/jpeg;base64,${base64ImageBytes}`;
  } catch (error) {
    console.error("Image generation error:", error);
    throw error;
  }
};

export const generateVideo = async (
  prompt: string,
  aspectRatio: AspectRatio
): Promise<string> => {
  // Veo specifically requires the user to select a key in some environments
  await checkApiKeySelection();

  // Re-instantiate after potential key selection
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // STRICT VALIDATION: Veo only supports 16:9 or 9:16.
  // We do not auto-correct here to respect the application's validation logic.
  if (aspectRatio !== '16:9' && aspectRatio !== '9:16') {
    throw new Error("Video generation currently only supports 16:9 (Landscape) and 9:16 (Portrait) aspect ratios.");
  }

  try {
    let operation = await ai.models.generateVideos({
      model: VEO_MODEL,
      prompt: prompt,
      config: {
        numberOfVideos: 1,
        resolution: '720p', // fast-generate-preview works well with 720p
        aspectRatio: aspectRatio,
      }
    });

    // Poll for completion
    while (!operation.done) {
      // Wait 5 seconds before next poll
      await new Promise(resolve => setTimeout(resolve, 5000));
      operation = await ai.operations.getVideosOperation({ operation: operation });
    }

    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    if (!downloadLink) {
      throw new Error("Video generation failed or no URI returned.");
    }

    // Fetch the actual video bytes
    const videoResponse = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    if (!videoResponse.ok) {
      throw new Error("Failed to download generated video.");
    }

    const videoBlob = await videoResponse.blob();
    // Convert to Base64 to allow LocalStorage persistence (Blob URLs expire on session end)
    return await blobToBase64(videoBlob);

  } catch (error) {
    console.error("Video generation error:", error);
    throw error;
  }
};
```

## App.tsx

Add state variables and UI components for Style Presets, Negative Prompts, and Seed control.

```tsx
import React, { useState, useRef, useEffect } from 'react';
import { Header } from './components/Header';
import { MediaCard } from './components/MediaCard';
import { LoadingState } from './components/LoadingState';
import { GeneratedItem, MediaType, AspectRatio, AdvancedOptions } from './types';
import { generateImage, generateVideo } from './services/gemini';
import { Sparkles, Film, Image as ImageIcon, AlertCircle, Settings2, ChevronDown, ChevronUp, Dices } from 'lucide-react';

const DEFAULT_PROMPT = "A woman, exuberantly smiling and wearing sunglasses and a red jacket, leans forward against a vibrant blue sky. Behind her, a red car speeds by on a sunlit street, with a rusted metal fence as a backdrop. The image exudes energy, joy, and a sense of carefree movement.";
const STORAGE_KEY = 'solaris_history';

const STYLE_PRESETS = [
  'None',
  'Photorealistic',
  'Cinematic',
  'Anime',
  'Digital Art',
  'Oil Painting',
  'Cyberpunk',
  'Watercolor',
  '3D Render',
  'Sketch'
];

function App() {
  const [prompt, setPrompt] = useState(DEFAULT_PROMPT);
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>('16:9');
  const [mediaType, setMediaType] = useState<MediaType>(MediaType.IMAGE);
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Advanced Options State
  const [showAdvanced, setShowAdvanced] = useState(false);
  const [stylePreset, setStylePreset] = useState('None');
  const [negativePrompt, setNegativePrompt] = useState('');
  const [seed, setSeed] = useState<number | undefined>(undefined);

  // Initialize history from localStorage
  const [history, setHistory] = useState<GeneratedItem[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : [];
    } catch (err) {
      console.error("Failed to load history:", err);
      return [];
    }
  });

  // Save history to localStorage whenever it changes
  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(history));
    } catch (err) {
      console.error("Failed to save history:", err);
    }
  }, [history]);

  const galleryRef = useRef<HTMLDivElement>(null);

  const handleGenerate = async () => {
    // 1. Validate Prompt
    if (!prompt.trim()) {
      setError("Please enter a description for your creation.");
      return;
    }

    // 2. Validate Aspect Ratio for Video
    if (mediaType === MediaType.VIDEO) {
      const validVideoRatios: AspectRatio[] = ['16:9', '9:16'];
      if (!validVideoRatios.includes(aspectRatio)) {
        setError("Veo video generation only supports 16:9 (Landscape) and 9:16 (Portrait) aspect ratios. Please select a valid ratio.");
        return;
      }
    }

    setIsGenerating(true);
    setError(null);

    // Scroll to gallery
    setTimeout(() => {
      galleryRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 100);

    try {
      let url = '';
      const advancedOptions: AdvancedOptions = {
        stylePreset,
        negativePrompt: negativePrompt.trim() || undefined,
        seed
      };

      if (mediaType === MediaType.IMAGE) {
        url = await generateImage(prompt, aspectRatio, advancedOptions);
      } else {
        url = await generateVideo(prompt, aspectRatio);
      }

      const newItem: GeneratedItem = {
        id: crypto.randomUUID(),
        type: mediaType,
        url,
        prompt,
        timestamp: Date.now(),
        aspectRatio,
        advancedOptions: mediaType === MediaType.IMAGE ? advancedOptions : undefined
      };

      setHistory(prev => [newItem, ...prev]);
    } catch (err: any) {
      setError(err.message || "An unknown error occurred during generation.");
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <Header />

      <main className="flex-1 flex flex-col">
        {/* Hero / Input Section */}
        <section className="relative bg-white border-b border-slate-200 overflow-hidden">
          <div className="absolute inset-0 bg-gradient-to-br from-brand-blue/5 to-brand-red/5 pointer-events-none"></div>

          <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-12 lg:py-16 relative">
            <div className="text-center mb-8">
              <h1 className="text-4xl md:text-5xl font-extrabold tracking-tight text-slate-900 mb-4">
                Visualize the <span className="text-transparent bg-clip-text bg-gradient-to-r from-brand-blue to-brand-red">Extraordinary</span>
              </h1>
              <p className="text-lg text-slate-600 max-w-2xl mx-auto">
                Transform your words into vivid images and videos using the power of Google's Gemini & Veo models.
              </p>
            </div>

            <div className="bg-white rounded-2xl shadow-xl border border-slate-200 p-4 md:p-6 transition-all duration-300">
              <div className="relative">
                <textarea
                  value={prompt}
                  onChange={(e) => {
                    setPrompt(e.target.value);
                    if (error && e.target.value.trim()) setError(null);
                  }}
                  placeholder="Describe what you want to see..."
                  className={`w-full h-32 p-4 text-lg text-slate-800 placeholder:text-slate-400 bg-slate-50 rounded-xl border focus:ring-2 focus:ring-brand-blue resize-none transition-shadow ${error && !prompt.trim() ? 'border-red-300 focus:ring-red-200' : 'border-transparent'}`}
                />
                <div className="absolute bottom-3 right-3 text-xs text-slate-400 bg-slate-100 px-2 py-1 rounded-md">
                  {prompt.length} chars
                </div>
              </div>

              <div className="mt-4 flex flex-col md:flex-row items-center justify-between gap-4">

                {/* Controls */}
                <div className="flex flex-wrap items-center gap-4 w-full md:w-auto justify-center md:justify-start">
                  {/* Mode Toggle */}
                  <div className="flex bg-slate-100 p-1 rounded-lg border border-slate-200">
                    <button
                      onClick={() => {
                        setMediaType(MediaType.IMAGE);
                        setError(null);
                      }}
                      className={`flex items-center gap-2 px-4 py-2 rounded-md text-sm font-medium transition-all ${
                        mediaType === MediaType.IMAGE 
                          ? 'bg-white text-brand-blue shadow-sm' 
                          : 'text-slate-500 hover:text-slate-700'
                      }`}
                    >
                      <ImageIcon className="w-4 h-4" />
                      Image
                    </button>
                    <button
                      onClick={() => {
                        setMediaType(MediaType.VIDEO);
                        setError(null);
                        // Close advanced options if switching to video
                        setShowAdvanced(false);
                      }}
                      className={`flex items-center gap-2 px-4 py-2 rounded-md text-sm font-medium transition-all ${
                        mediaType === MediaType.VIDEO
                          ? 'bg-white text-brand-red shadow-sm' 
                          : 'text-slate-500 hover:text-slate-700'
                      }`}
                    >
                      <Film className="w-4 h-4" />
                      Video
                    </button>
                  </div>

                  {/* Aspect Ratio */}
                  <select
                    value={aspectRatio}
                    onChange={(e) => {
                      setAspectRatio(e.target.value as AspectRatio);
                      setError(null);
                    }}
                    className="px-3 py-2 bg-slate-100 border-0 rounded-lg text-sm font-medium text-slate-700 focus:ring-2 focus:ring-brand-blue cursor-pointer hover:bg-slate-200 transition-colors"
                  >
                    <option value="1:1" disabled={mediaType === MediaType.VIDEO}>Square (1:1) {mediaType === MediaType.VIDEO ? '(Image only)' : ''}</option>
                    <option value="16:9">Landscape (16:9)</option>
                    <option value="9:16">Portrait (9:16)</option>
                    <option value="4:3" disabled={mediaType === MediaType.VIDEO}>Standard (4:3) {mediaType === MediaType.VIDEO ? '(Image only)' : ''}</option>
                    <option value="3:4" disabled={mediaType === MediaType.VIDEO}>Vertical (3:4) {mediaType === MediaType.VIDEO ? '(Image only)' : ''}</option>
                  </select>
                </div>

                {/* Generate Button */}
                <button
                  onClick={handleGenerate}
                  disabled={isGenerating}
                  className={`w-full md:w-auto px-8 py-3 rounded-xl flex items-center justify-center gap-2 font-bold text-white shadow-lg shadow-brand-blue/20 transition-all transform active:scale-95 ${
                    isGenerating
                      ? 'bg-slate-300 cursor-not-allowed'
                      : 'bg-gradient-to-r from-brand-blue to-brand-red hover:shadow-xl hover:brightness-110'
                  }`}
                >
                  {isGenerating ? (
                    <span className="flex items-center gap-2">
                      Thinking...
                    </span>
                  ) : (
                    <span className="flex items-center gap-2">
                      <Sparkles className="w-5 h-5" />
                      Generate
                    </span>
                  )}
                </button>
              </div>

              {/* Advanced Options Toggle */}
              {mediaType === MediaType.IMAGE && (
                <div className="mt-4 border-t border-slate-100 pt-4">
                  <button
                    onClick={() => setShowAdvanced(!showAdvanced)}
                    className="flex items-center gap-2 text-sm font-medium text-slate-600 hover:text-brand-blue transition-colors select-none"
                  >
                    <Settings2 className="w-4 h-4" />
                    <span>Advanced Options</span>
                    {showAdvanced ? <ChevronUp className="w-3 h-3" /> : <ChevronDown className="w-3 h-3" />}
                  </button>

                  {/* Advanced Options Panel */}
                  {showAdvanced && (
                    <div className="mt-4 grid grid-cols-1 md:grid-cols-3 gap-6 animate-in fade-in slide-in-from-top-2 duration-200">

                      {/* Style Preset */}
                      <div className="space-y-1.5">
                        <label className="text-xs font-semibold text-slate-500 uppercase tracking-wider">Style</label>
                        <select
                          value={stylePreset}
                          onChange={(e) => setStylePreset(e.target.value)}
                          className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm text-slate-700 focus:ring-2 focus:ring-brand-blue focus:border-transparent"
                        >
                          {STYLE_PRESETS.map(style => (
                            <option key={style} value={style}>{style}</option>
                          ))}
                        </select>
                      </div>

                      {/* Negative Prompt */}
                      <div className="space-y-1.5">
                        <label className="text-xs font-semibold text-slate-500 uppercase tracking-wider">Negative Prompt</label>
                        <input
                          type="text"
                          value={negativePrompt}
                          onChange={(e) => setNegativePrompt(e.target.value)}
                          placeholder="e.g., blurry, low quality"
                          className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm text-slate-700 focus:ring-2 focus:ring-brand-blue focus:border-transparent placeholder:text-slate-400"
                        />
                      </div>

                      {/* Seed */}
                      <div className="space-y-1.5">
                        <label className="text-xs font-semibold text-slate-500 uppercase tracking-wider">Seed</label>
                        <div className="relative">
                          <input
                            type="number"
                            value={seed ?? ''}
                            onChange={(e) => setSeed(e.target.value ? parseInt(e.target.value) : undefined)}
                            placeholder="Random"
                            className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm text-slate-700 focus:ring-2 focus:ring-brand-blue focus:border-transparent placeholder:text-slate-400"
                          />
                          <button 
                            onClick={() => setSeed(Math.floor(Math.random() * 1000000))}
                            className="absolute right-2 top-1/2 -translate-y-1/2 p-1.5 text-slate-400 hover:text-brand-blue hover:bg-slate-200 rounded transition-colors"
                            title="Randomize Seed"
                          >
                            <Dices className="w-4 h-4" />
                          </button>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>
        </section>

        {/* Results Section */}
        <section 
          ref={galleryRef} 
          className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-12"
        >
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-2xl font-bold text-slate-900">Gallery</h2>
            <span className="text-sm text-slate-500">{history.length} items generated</span>
          </div>

          {error && (
            <div className="mb-8 p-4 bg-red-50 border border-red-100 rounded-xl flex items-start gap-3 text-red-800 animate-pulse-slow">
              <AlertCircle className="w-5 h-5 shrink-0 mt-0.5" />
              <div>
                <h3 className="font-semibold">Validation Error</h3>
                <p className="text-sm opacity-90">{error}</p>
                {error.includes("key") && (
                  <button 
                    onClick={() => window.aistudio?.openSelectKey()}
                    className="mt-2 text-xs font-bold underline hover:text-red-950"
                  >
                    Re-select API Key
                  </button>
                )}
              </div>
            </div>
          )}

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {isGenerating && (
               <div className="col-span-1">
                 <LoadingState 
                   message={mediaType === MediaType.VIDEO 
                     ? "Crafting video frames... This typically takes 30-60 seconds." 
                     : "Painting pixels... Almost there."} 
                 />
               </div>
            )}

            {history.map((item) => (
              <MediaCard key={item.id} item={item} />
            ))}

            {!isGenerating && history.length === 0 && !error && (
              <div className="col-span-full flex flex-col items-center justify-center py-24 text-center text-slate-400 border-2 border-dashed border-slate-200 rounded-2xl bg-slate-50/50">
                <div className="p-4 bg-slate-100 rounded-full mb-4">
                   <Sparkles className="w-8 h-8 text-slate-300" />
                </div>
                <p className="text-lg font-medium mb-1">Your canvas is empty</p>
                <p className="text-sm">Enter a prompt above to start creating.</p>
              </div>
            )}
          </div>
        </section>
      </main>
    </div>
  );
}

export default App;
```

