  const [isSaving, setIsSaving] = useState(false);

  const handleDownload = (e: React.MouseEvent) => {
    e.stopPropagation(); // Prevent bubbling
    const link = document.createElement('a');
    link.href = item.url;
    link.download = `solaris-${item.type.toLowerCase()}-${item.timestamp}.${item.type === MediaType.VIDEO ? 'mp4' : 'svg'}`; // Default to svg if not video, browser handles ext usually
    if (item.type === MediaType.IMAGE) link.download = link.download.replace('.svg', '.jpg');

    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const toggleVideo = () => {
